// --- Transliteration ---
function makeSlug($title) {
    $slug = mb_strtolower($title, 'UTF-8');
    $tr = [
        'а'=>'a','б'=>'b','в'=>'v','г'=>'g','д'=>'d','е'=>'e','ё'=>'yo',
        'ж'=>'zh','з'=>'z','и'=>'i','й'=>'y','к'=>'k','л'=>'l','м'=>'m',
        'н'=>'n','о'=>'o','п'=>'p','р'=>'r','с'=>'s','т'=>'t','у'=>'u',
        'ф'=>'f','х'=>'h','ц'=>'ts','ч'=>'ch','ш'=>'sh','щ'=>'sch',
        'ъ'=>'','ы'=>'y','ь'=>'','э'=>'e','ю'=>'yu','я'=>'ya'
    ];
    $slug = strtr($slug, $tr);
    $slug = preg_replace('/[^a-z0-9]+/', '-', $slug);
    return trim($slug, '-');
}

// --- SEO content generator ---
function seo($title, $intro, $whatAwaits, $audience, $adv1, $adv2) {
    $lis = implode('', array_map(fn($a) => '<li>' . $a . '</li>', $audience));
    return '<p><strong>Всероссийская олимпиада «' . $title . '»</strong> — ' . $intro . '.</p>' .
        '<h3>Что вас ждёт</h3><p>' . $whatAwaits . '.</p>' .
        '<h3>Кому подойдёт</h3><ul>' . $lis . '</ul>' .
        '<h3>Преимущества участия</h3><ul>' .
        '<li>Участие <strong>полностью бесплатное</strong> — проходите тест в удобное время</li>' .
        '<li>Диплом I, II или III степени для портфолио при аттестации — 169 руб.</li>' .
        '<li>' . $adv1 . '</li>' .
        '<li>' . $adv2 . '</li></ul>';
}

// --- Insert olympiad ---
function insertOlympiad($db, $o, &$order) {
    $slug = makeSlug($o['title']);

    // Check if slug exists
    $check = $db->prepare("SELECT id FROM olympiads WHERE slug = ?");
    $check->execute([$slug]);
    if ($check->fetch()) {
        echo "  SKIP (exists): {$o['title']}\n";
        return null;
    }

    $stmt = $db->prepare("INSERT INTO olympiads (title, slug, description, seo_content, target_audience, subject, grade, diploma_price, is_active, display_order) VALUES (?,?,?,?,?,?,NULL,169.00,1,?)");
    $stmt->execute([$o['title'], $slug, $o['desc'], $o['seo'], $o['ta'], $o['subj'], $order]);
    $id = $db->lastInsertId();
    $order++;

    // Questions
    foreach ($o['questions'] as $i => $q) {
        $db->prepare("INSERT INTO olympiad_questions (olympiad_id, question_text, options, correct_option_index, display_order) VALUES (?,?,?,?,?)")
            ->execute([$id, $q[0], json_encode($q[1], JSON_UNESCAPED_UNICODE), $q[2], $i + 1]);
    }

    // Audience types
    foreach ($o['at'] as $atId) {
        $db->prepare("INSERT IGNORE INTO olympiad_audience_types (olympiad_id, audience_type_id) VALUES (?,?)")
            ->execute([$id, $atId]);
    }

    // Audience category
    $db->prepare("INSERT IGNORE INTO olympiad_audience_categories (olympiad_id, category_id) VALUES (?,?)")
        ->execute([$id, $o['cat']]);

    // Specialization
    $db->prepare("INSERT IGNORE INTO olympiad_specializations (olympiad_id, specialization_id) VALUES (?,?)")
        ->execute([$id, $o['spec']]);

    echo "  OK #{$id}: {$o['title']}\n";
    return $id;
}

